     3|
     4|const STORAGE_KEY = "viajero-wishlist"
     5|const RECENT_KEY = "viajero-recently-viewed"
     6|
     7|export function getWishlistCount(): number {
     8|  if (typeof window === "undefined") return 0
     9|  try { const f = JSON.parse(localStorage.getItem("viajero_favs") || "[]"); return f.length } catch { return 0 }
    10|}
    11|
    12|export function useWishlist() {
    13|  const [items, setItems] = useState<string[]>([])
    14|  const [loaded, setLoaded] = useState(false)
    15|
    16|  useEffect(() => {
    17|    try {
    18|      const saved = localStorage.getItem(STORAGE_KEY)
    19|      if (saved) setItems(JSON.parse(saved))
    20|    } catch {}
    21|    setLoaded(true)
    22|  }, [])
    23|
    24|  useEffect(() => {
    25|    if (loaded) localStorage.setItem(STORAGE_KEY, JSON.stringify(items))
    26|  }, [items, loaded])
    27|
    28|  const toggle = (name: string) => {
    29|    setItems((prev) => (prev.includes(name) ? prev.filter((n) => n !== name) : [...prev, name]))
    30|  }
    31|
    32|  const isWished = (name: string) => items.includes(name)
    33|  const clear = () => setItems([])
    34|
    35|  return { items, toggle, isWished, clear }
    36|}
    37|
    38|export function useRecentlyViewed() {
    39|  const [items, setItems] = useState<string[]>([])
    40|  const [loaded, setLoaded] = useState(false)
    41|
    42|  useEffect(() => {
    43|    try {
    44|      const saved = localStorage.getItem(RECENT_KEY)
    45|      if (saved) setItems(JSON.parse(saved))
    46|    } catch {}
    47|    setLoaded(true)
    48|  }, [])
    49|
    50|  const add = (name: string) => {
